from core.serpents.oracle import Oracle


class Skeptic:
    """
    Keeper of Verification.

    Reviews theories produced by the Council and
    assigns an initial verification status.
    """

    def review(self, theories: list[dict]) -> list[dict]:

        results = []

        for theory in theories:

            confidence = theory["confidence"]

            if confidence == "high":
                status = "Requires Evidence"

            elif confidence == "medium":
                status = "Plausible"

            else:
                status = "Speculative"

            results.append(
                {
                    "theory": theory["hypothesis"],
                    "confidence": confidence,
                    "status": status,
                }
            )

        return results